/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp) followed by EOF. */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token t = in.readToken();
    if (t != null) {
      throw new ParseException("Expected end of input but found " + t);
    }
    return result;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *            | let <def>+ in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token peek = in.peek();
    if (peek == Lexer.IF) {
      return parseIf();
    } else if (peek == Lexer.LET) {
      return parseLet();
    } else if (peek == Lexer.MAP) {
      return parseMap();
    } else {
      // BinaryExp: Term { BinOp Term }*
      AST result = parseTerm();
      while (in.peek() instanceof OpToken && ((OpToken) in.peek()).isBinOp()) {
        OpToken opTok = (OpToken) in.readToken();
        BinOp op = opTok.toBinOp();
        AST right = parseTerm();
        result = new BinOpApp(op, result, right);
      }
      return result;
    }
  }

  /** Parses: if <exp> then <exp> else <exp> */
  private AST parseIf() {
    in.readToken(); // consume 'if'
    AST test = parseExp();
    Token t = in.readToken();
    if (t != Lexer.THEN) {
      throw new ParseException("Expected 'then' but found " + t);
    }
    AST conseq = parseExp();
    t = in.readToken();
    if (t != Lexer.ELSE) {
      throw new ParseException("Expected 'else' but found " + t);
    }
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let <def>+ in <exp> */
  private AST parseLet() {
    in.readToken(); // consume 'let'
    ArrayList<Def> defs = new ArrayList<Def>();
    defs.add(parseDef());
    while (in.peek() != Lexer.IN) {
      defs.add(parseDef());
    }
    in.readToken(); // consume 'in'
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: <id> := <exp> ; */
  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable)) {
      throw new ParseException("Expected variable in definition but found " + t);
    }
    Variable v = (Variable) t;
    t = in.readToken();
    if (t != Lexer.BIND) {
      throw new ParseException("Expected ':=' but found " + t);
    }
    AST exp = parseExp();
    t = in.readToken();
    if (!(t instanceof SemiColon)) {
      throw new ParseException("Expected ';' but found " + t);
    }
    return new Def(v, exp);
  }

  /** Parses: map <id-list> to <exp> */
  private AST parseMap() {
    in.readToken(); // consume 'map'
    Variable[] vars = parseIdList();
    Token t = in.readToken();
    if (t != Lexer.TO) {
      throw new ParseException("Expected 'to' but found " + t);
    }
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: { <prop-id-list> }
    *   <id-list> ::= { <prop-id-list> }
    *   <prop-id-list> ::= <id> { , <id> }*
    */
  private Variable[] parseIdList() {
    if (!(in.peek() instanceof Variable)) {
      return new Variable[0];
    }
    ArrayList<Variable> vars = new ArrayList<Variable>();
    vars.add((Variable) in.readToken());
    while (in.peek() instanceof Comma) {
      in.readToken(); // consume ','
      Token t = in.readToken();
      if (!(t instanceof Variable)) {
        throw new ParseException("Expected variable in id list but found " + t);
      }
      vars.add((Variable) t);
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses:
    *   <term> ::= <unop> <term>
    *            | <factor> { ( <exp-list> ) }
    *            | <empty>
    *            | <int>
    *            | <bool>
    */
  private AST parseTerm() {
    Token peek = in.peek();

    // UnOp Term
    if (peek instanceof OpToken && ((OpToken) peek).isUnOp()) {
      OpToken opTok = (OpToken) in.readToken();
      UnOp op = opTok.toUnOp();
      AST arg = parseTerm();
      return new UnOpApp(op, arg);
    }

    // Int
    if (peek instanceof IntConstant) {
      return (IntConstant) in.readToken();
    }

    // Bool
    if (peek instanceof BoolConstant) {
      return (BoolConstant) in.readToken();
    }

    // Empty
    if (peek instanceof EmptyConstant) {
      in.readToken();
      return (EmptyConstant) peek;
    }

    // Factor { ( ExpList ) }
    AST factor = parseFactor();
    if (in.peek() instanceof LeftParen) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      Token t = in.readToken();
      if (!(t instanceof RightParen)) {
        throw new ParseException("Expected ')' but found " + t);
      }
      return new App(factor, args);
    }
    return factor;
  }

  /** Parses: ( <exp> ) | <prim> | <id> */
  private AST parseFactor() {
    Token peek = in.peek();

    if (peek instanceof LeftParen) {
      in.readToken(); // consume '('
      AST exp = parseExp();
      Token t = in.readToken();
      if (!(t instanceof RightParen)) {
        throw new ParseException("Expected ')' but found " + t);
      }
      return exp;
    }

    if (peek instanceof PrimFun) {
      return (PrimFun) in.readToken();
    }

    if (peek instanceof Variable) {
      return (Variable) in.readToken();
    }

    throw new ParseException("Expected expression but found " + peek);
  }

  /** Parses: { <prop-exp-list> }
    *   <exp-list> ::= { <prop-exp-list> }
    *   <prop-exp-list> ::= <exp> { , <exp> }*
    */
  private AST[] parseExpList() {
    if (in.peek() instanceof RightParen) {
      return new AST[0];
    }
    ArrayList<AST> exps = new ArrayList<AST>();
    exps.add(parseExp());
    while (in.peek() instanceof Comma) {
      in.readToken(); // consume ','
      exps.add(parseExp());
    }
    return exps.toArray(new AST[0]);
  }
}

import junit.framework.*;
import java.io.*;

public class AgentTest extends TestCase {

  public AgentTest(String name) {
    super(name);
  }

  private void checkString(String name, String answer, String program) {
    Parser p = new Parser(new StringReader(program));
    assertEquals(name, answer, p.parse().toString());
  }

  private void checkError(String name, String program) {
    try {
      Parser p = new Parser(new StringReader(program));
      p.parse();
      fail(name + " should have thrown ParseException");
    } catch (ParseException e) {
      // expected
    }
  }

  // --- Constants ---

  public void testInt() {
    checkString("int", "42", "42");
  }

  public void testTrue() {
    checkString("true", "true", "true");
  }

  public void testFalse() {
    checkString("false", "false", "false");
  }

  public void testEmpty() {
    checkString("empty", "empty", "empty");
  }

  // --- Primitive functions ---

  public void testNumberP() {
    checkString("number?", "number?", "number?");
  }

  public void testFunctionP() {
    checkString("function?", "function?", "function?");
  }

  public void testListP() {
    checkString("list?", "list?", "list?");
  }

  public void testEmptyP() {
    checkString("empty?", "empty?", "empty?");
  }

  public void testConsP() {
    checkString("cons?", "cons?", "cons?");
  }

  public void testCons() {
    checkString("cons", "cons", "cons");
  }

  public void testFirst() {
    checkString("first", "first", "first");
  }

  public void testRest() {
    checkString("rest", "rest", "rest");
  }

  public void testArity() {
    checkString("arity", "arity", "arity");
  }

  // --- Variables ---

  public void testVariable() {
    checkString("var", "x", "x");
  }

  public void testVariableUnderscore() {
    checkString("var_", "x_y", "x_y");
  }

  public void testVariableQuestion() {
    checkString("var?", "foo?bar", "foo?bar");
  }

  // --- Unary operators ---

  public void testUnaryPlus() {
    checkString("unary+", "+ 3", "+3");
  }

  public void testUnaryMinus() {
    checkString("unary-", "- 3", "-3");
  }

  public void testUnaryTilde() {
    checkString("tilde", "~ true", "~true");
  }

  public void testDoubleNeg() {
    checkString("double neg", "- - 3", "- -3");
  }

  public void testDoubleTilde() {
    checkString("double tilde", "~ ~ false", "~~false");
  }

  // --- Binary operators ---

  public void testAdd() {
    checkString("add", "(2 + 3)", "2+3");
  }

  public void testSub() {
    checkString("sub", "(5 - 2)", "5-2");
  }

  public void testMul() {
    checkString("mul", "(3 * 4)", "3*4");
  }

  public void testDiv() {
    checkString("div", "(10 / 2)", "10/2");
  }

  public void testEquals() {
    checkString("eq", "(x = y)", "x = y");
  }

  public void testNotEquals() {
    checkString("neq", "(x != y)", "x != y");
  }

  public void testLessThan() {
    checkString("lt", "(x < y)", "x < y");
  }

  public void testGreaterThan() {
    checkString("gt", "(x > y)", "x > y");
  }

  public void testLessThanEquals() {
    checkString("lte", "(x <= y)", "x <= y");
  }

  public void testGreaterThanEquals() {
    checkString("gte", "(x >= y)", "x >= y");
  }

  public void testAnd() {
    checkString("and", "(x & y)", "x & y");
  }

  public void testOr() {
    checkString("or", "(x | y)", "x | y");
  }

  // --- Left associativity ---

  public void testLeftAssocAdd() {
    checkString("left assoc add", "((1 + 2) + 3)", "1+2+3");
  }

  public void testLeftAssocMixed() {
    checkString("left assoc mixed", "((1 + 2) * 3)", "1+2*3");
  }

  public void testLeftAssocThree() {
    checkString("left assoc three", "(((a + b) - c) * d)", "a + b - c * d");
  }

  // --- Function application ---

  public void testAppNoArgs() {
    checkString("app no args", "f()", "f()");
  }

  public void testAppOneArg() {
    checkString("app one arg", "f(x)", "f(x)");
  }

  public void testAppTwoArgs() {
    checkString("app two args", "f(x, y)", "f(x, y)");
  }

  public void testAppThreeArgs() {
    checkString("app three args", "f(x, y, z)", "f(x, y, z)");
  }

  public void testConsApp() {
    checkString("cons app", "cons(1, empty)", "cons(1, empty)");
  }

  public void testFirstApp() {
    checkString("first app", "first(x)", "first(x)");
  }

  public void testNestedApp() {
    checkString("nested app", "f(g(x))", "f(g(x))");
  }

  public void testParenApp() {
    // (f) reduces to f, so (f)(x) prints as f(x)
    checkString("paren app", "f(x)", "(f)(x)");
  }

  // --- If-then-else ---

  public void testSimpleIf() {
    checkString("simple if", "if true then 1 else 2", "if true then 1 else 2");
  }

  public void testNestedIf() {
    checkString("nested if",
      "if true then if false then 1 else 2 else 3",
      "if true then if false then 1 else 2 else 3");
  }

  public void testIfWithBinop() {
    checkString("if with binop",
      "if (x < 0) then (0 - x) else x",
      "if x < 0 then 0 - x else x");
  }

  // --- Let ---

  public void testSimpleLet() {
    checkString("simple let", "let x := 5; in x", "let x := 5; in x");
  }

  public void testMultipleDefs() {
    checkString("multiple defs",
      "let x := 1; y := 2; in (x + y)",
      "let x := 1; y := 2; in x + y");
  }

  public void testLetWithExpr() {
    checkString("let with expr",
      "let x := (1 + 2); in (x * 3)",
      "let x := 1 + 2; in x * 3");
  }

  // --- Map ---

  public void testMapNoArgs() {
    checkString("map no args", "map  to 0", "map to 0");
  }

  public void testMapOneArg() {
    checkString("map one arg", "map x to x", "map x to x");
  }

  public void testMapTwoArgs() {
    checkString("map two args", "map x,y to (x + y)", "map x,y to x+y");
  }

  public void testMapThreeArgs() {
    checkString("map three args", "map x,y,z to x", "map x,y,z to x");
  }

  // --- Parenthesized expressions ---

  public void testParenExpr() {
    checkString("paren", "3", "(3)");
  }

  public void testParenBinop() {
    checkString("paren binop", "(1 + (2 * 3))", "1 + (2 * 3)");
  }

  // --- Complex expressions ---

  public void testComplexExpr() {
    checkString("complex",
      "(f(x) + (x * 12))",
      "f(x) + (x * 12)");
  }

  public void testBinopWithUnop() {
    checkString("binop with unop", "(1 + - 2)", "1 + -2");
  }

  public void testLetInIf() {
    checkString("let in if",
      "if true then let x := 1; in x else 0",
      "if true then let x := 1; in x else 0");
  }

  public void testMapApp() {
    checkString("map app",
      "(map x to x)(5)",
      "(map x to x)(5)");
  }

  public void testIfApp() {
    checkString("if app",
      "(if true then f else g)(x)",
      "(if true then f else g)(x)");
  }

  // --- Error cases ---

  public void testEmptyInput() {
    checkError("empty input", "");
  }

  public void testExtraTokens() {
    checkError("extra tokens", "1 2");
  }

  public void testMissingThen() {
    checkError("missing then", "if true 1 else 2");
  }

  public void testMissingElse() {
    checkError("missing else", "if true then 1");
  }

  public void testMissingIn() {
    checkError("missing in", "let x := 5; x");
  }

  public void testMissingTo() {
    checkError("missing to", "map x x");
  }

  public void testMissingSemicolon() {
    checkError("missing semicolon", "let x := 5 in x");
  }

  public void testMissingRParen() {
    checkError("missing rparen", "(3");
  }

  public void testStarAtStart() {
    checkError("star at start", "* 3");
  }

  public void testBracket() {
    checkError("bracket", "[1]");
  }

  public void testLetNoDefs() {
    checkError("let no defs", "let in x");
  }

  public void testDefNotVar() {
    checkError("def not var", "let 5 := 5; in 5");
  }
}

